// ============================================================
// Cross-scope structural assertions
// ============================================================
test.describe('IANA Validation — structural', () => {
  test('export formats are valid', () => {
    const data = loadExploration('main');

    // Mermaid
    expect(data.mermaid).toMatch(/stateDiagram|graph/);

    // DOT
    expect(data.dot).toContain('digraph {');
    expect(data.dot.trimEnd()).toMatch(/}$/);

    // JSON round-trip
    const roundTripped = JSON.parse(JSON.stringify(data.graph)) as SerializedGraph;
    expect(roundTripped.states).toBeDefined();
    expect(roundTripped.transitions).toBeDefined();
  });

  test('idempotence — main and body-content share root facts', () => {
    const main = loadExploration('main');
    const bodyContent = loadExploration('body-content');

    // Both should detect RFC links
    const mainRoot = getRootState(main);
    const bcRoot = getRootState(bodyContent);
    const mainRfcLinks = mainRoot.facts.filter((f) => (f.text ?? '').includes('RFC'));
    const bcRfcLinks = bcRoot.facts.filter((f) => (f.text ?? '').includes('RFC'));
    expect(mainRfcLinks).toHaveLength(bcRfcLinks.length);
  });

  test('scopes are disjoint — header vs footer', () => {
    const header = loadExploration('header');
    const footer = loadExploration('footer');

    const headerUids = new Set(getRootState(header).facts.map((f) => f.uid));
    const footerUids = new Set(getRootState(footer).facts.map((f) => f.uid));

    // uid is index-based (a[0], a[1]...) so they may collide on index
    // but text content should be different
    const headerTexts = new Set(getRootState(header).facts.map((f) => f.text));
    const footerTexts = new Set(getRootState(footer).facts.map((f) => f.text));
    const overlap = [...headerTexts].filter((t) => footerTexts.has(t));
    // Very few overlaps expected (maybe "About" appears in both)
    expect(overlap.length).toBeLessThan(3);
  });

  test('navigation URLs are real HTTP(S)', () => {
    const data = loadExploration('body');
    const navTransitions = getNavigationTransitions(data);
    for (const t of navTransitions) {
      const url = new URL(t.navigationUrl!);
      expect(['http:', 'https:']).toContain(url.protocol);
    }
  });
});
